public static Map<String, Integer> countWords(List<String> words) {
    Map<String, Integer> counts = new HashMap<>();
    for (String word : words) {
        counts.put(word, counts.getOrDefault(word, 0) + 1);
    }
    return counts;
}

public static boolean isPalindrome(String s) {
    if (s == null) return false;
    String lower = s.toLowerCase();
    String reversed = new StringBuilder(lower).reverse().toString();
    return lower.equals(reversed);
}

public static List<String> findDuplicates(List<String> items) {
    Set<String> seen = new HashSet<>();
    Set<String> duplicates = new HashSet<>();
    for (String item : items) {
        if (!seen.add(item)) {
            duplicates.add(item);
        }
    }
    return new ArrayList<>(duplicates);
}

public static List<String> validateRequiredFields(Map<String, String> data, List<String> required) {
    List<String> invalid = new ArrayList<>();
    for (String field : required) {
        String value = data.get(field);
        if (value == null || value.isBlank()) {
            invalid.add(field);
        }
    }
    return invalid;
}

public static boolean waitForCondition(BooleanSupplier condition, long timeoutMs) {
    long start = System.currentTimeMillis();
    while (System.currentTimeMillis() - start < timeoutMs) {
        if (condition.getAsBoolean()) {
            return true;
        }
        try {
            Thread.sleep(500);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return false;
        }
    }
    return condition.getAsBoolean();
}

public static List<Object> extractField(List<Map<String, Object>> rows, String key) {
    List<Object> result = new ArrayList<>();
    for (Map<String, Object> row : rows) {
        if (row.containsKey(key)) {
            result.add(row.get(key));
        }
    }
    return result;
}

import java.util.Objects;

public static Map<String, String> diffMaps(Map<String, Object> expected, Map<String, Object> actual) {
    Map<String, String> diffs = new LinkedHashMap<>();
    for (String key : expected.keySet()) {
        if (!actual.containsKey(key)) {
            diffs.put("MISSING: " + key, "expected '" + expected.get(key) + "', got nothing");
        } else if (!Objects.equals(expected.get(key), actual.get(key))) {
            diffs.put("MISMATCH: " + key, "expected '" + expected.get(key) + "', got '" + actual.get(key) + "'");
        }
    }
    for (String key : actual.keySet()) {
        if (!expected.containsKey(key)) {
            diffs.put("EXTRA: " + key, "not in expected");
        }
    }
    return diffs;
}

public static List<String> removeDuplicates(List<String> items) {
    return new ArrayList<>(new LinkedHashSet<>(items));
}

public class RequestPayloadBuilder {
    private final Map<String, Object> fields = new LinkedHashMap<>();

    public RequestPayloadBuilder withField(String key, Object value) {
        fields.put(key, value);
        return this;
    }

    public Map<String, Object> build() {
        return new LinkedHashMap<>(fields);
    }
}

