public static Map<String, String> parseQueryString(String query) {
    Map<String, String> params = new LinkedHashMap<>();
    if (query == null || query.isBlank()) {
        return params;
    }
    String cleaned = query.startsWith("?") ? query.substring(1) : query;
    for (String pair : cleaned.split("&")) {
        String[] parts = pair.split("=", 2);
        String key = parts[0].trim();
        String value = parts.length > 1 ? parts[1].trim() : "";
        if (!key.isEmpty()) {
            params.put(key, value);
        }
    }
    return params;
}

public static Map<String, List<Map<String, Object>>> groupByField(
        List<Map<String, Object>> rows, String field) {
    Map<String, List<Map<String, Object>>> grouped = new LinkedHashMap<>();
    for (Map<String, Object> row : rows) {
        Object rawKey = row.get(field);
        String key = (rawKey != null) ? rawKey.toString() : "__unknown__";
        grouped.computeIfAbsent(key, k -> new ArrayList<>()).add(row);
    }
    return grouped;
}
